changeSet.sql:
drop trigger if exists trg_transcription_enforce_resource_id_immutable on gmdb.transcription;
create trigger trg_transcription_enforce_resource_id_immutable
    before update of details on gmdb.transcription
    for each row
    execute function gmdb.details_enforce_resource_id_immutable();

drop trigger if exists trg_transcription_default_resource_id on gmdb.transcription;
create trigger trg_transcription_default_resource_id
    before insert on gmdb.transcription
    for each row
    execute function gmdb.details_default_resource_id();
